import { useState } from "react";
import ProjectCard from "../components/ProjectCard";
import projects from "../data/projects";

function Portfolio() {
  const [activeCategory, setActiveCategory] = useState("All");

  const categories = ["All", "Games", "Apps", "Websites", "UI/UX"];

  const filteredProjects =
    activeCategory === "All"
      ? projects
      : projects.filter((proj) => proj.category === activeCategory);

  return (
    <section className="bg-[#0c0c0c] text-white px-6 py-24">
      <div className="max-w-7xl mx-auto">

        {/* Heading */}
        <div className="text-center mb-16">
          <h2 className="text-4xl md:text-5xl font-light tracking-tight mb-6">
            Selected Work
          </h2>

          <p className="text-gray-400 text-lg max-w-2xl mx-auto">
            Game prototypes. Interactive apps. Production websites.
            UI/UX case studies.  
            A hybrid exploration of design and development.
          </p>
        </div>

        {/* Category Filter */}
        <div className="flex justify-center gap-10 mb-16 border-b border-neutral-800 pb-4">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setActiveCategory(category)}
              className={`text-sm tracking-wide transition-all duration-300 ${
                activeCategory === category
                  ? "text-white border-b border-white pb-1"
                  : "text-gray-500 hover:text-white"
              }`}
            >
              {category}
            </button>
          ))}
        </div>

        {/* Project Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-16 transition-all duration-500">
          {filteredProjects.map((proj, i) => (
            <ProjectCard key={i} {...proj} />
          ))}
        </div>

      </div>
    </section>
  );
}

export default Portfolio;
